use-scoped-navigation-basic.raw:
"use client";

import { KeyboardProvider, useScope, useScopedNavigation } from "@diffgazer/keys";
import { useId, useRef, useState } from "react";

const commands = ["New File", "Open File", "Save", "Save As", "Close"];

function CommandPalette({ onClose }: { onClose: () => void }) {
  const listRef = useRef<HTMLDivElement>(null);
  const headingId = useId();

  useScope("command-palette");

  const { isHighlighted } = useScopedNavigation({
    containerRef: listRef,
    role: "option",
    wrap: true,
    onSelect: (value) => {
      alert(`Executed: ${value}`);
      onClose();
    },
  });

  return (
    <div style={{ marginTop: 8, padding: 8, border: "1px solid currentColor" }}>
      <h3 id={headingId}>Command Palette</h3>
      <p>ArrowUp/ArrowDown navigate; Enter executes.</p>
      <div ref={listRef} role="listbox" tabIndex={0} aria-labelledby={headingId}>
        {commands.map((cmd) => (
          // biome-ignore lint/a11y/useFocusableInteractive: WAI-ARIA listbox pattern — options stay non-focusable; the listbox container holds focus and active state is tracked via aria-selected.
          <div
            key={cmd}
            role="option"
            data-value={cmd}
            aria-selected={isHighlighted(cmd)}
            style={{ padding: "4px 8px", fontWeight: isHighlighted(cmd) ? 700 : 400 }}
          >
            {cmd}
          </div>
        ))}
      </div>
    </div>
  );
}

function App() {
  const [open, setOpen] = useState(false);

  return (
    <div>
      <button type="button" onClick={() => setOpen(true)}>
        Open Command Palette
      </button>
      {open && <CommandPalette onClose={() => setOpen(false)} />}
    </div>
  );
}

export default function UseScopedNavigationBasic() {
  return (
    <KeyboardProvider>
      <App />
    </KeyboardProvider>
  );
}

use-scoped-navigation-focus-within.raw:
"use client";

import { KeyboardProvider, useScopedNavigation } from "@diffgazer/keys";
import { useRef } from "react";

const left = ["Inbox", "Drafts", "Sent", "Archive"];
const right = ["Today", "This week", "Later"];

function List({ label, items }: { label: string; items: string[] }) {
  const listRef = useRef<HTMLDivElement>(null);

  // focusWithinOnly: arrow keys only drive the list whose focus is active, so
  // both lists coexist under one provider without an explicit scope each.
  const { isHighlighted } = useScopedNavigation({
    containerRef: listRef,
    role: "option",
    wrap: true,
    focusWithinOnly: true,
  });

  return (
    <div style={{ minWidth: 140 }}>
      <h4>{label}</h4>
      <div
        ref={listRef}
        role="listbox"
        aria-label={label}
        tabIndex={0}
        style={{ padding: 4, border: "1px solid currentColor" }}
      >
        {items.map((item) => (
          // biome-ignore lint/a11y/useFocusableInteractive: WAI-ARIA listbox pattern — options stay non-focusable; the listbox container holds focus and active state is tracked via aria-selected.
          <div
            key={item}
            role="option"
            data-value={item}
            aria-selected={isHighlighted(item)}
            style={{ padding: "4px 8px", fontWeight: isHighlighted(item) ? 700 : 400 }}
          >
            {item}
          </div>
        ))}
      </div>
    </div>
  );
}

export default function UseScopedNavigationFocusWithin() {
  return (
    <KeyboardProvider>
      <div>
        <p>Tab between the two listboxes. Arrow keys move only the focused list.</p>
        <div style={{ display: "flex", gap: 24 }}>
          <List label="Folders" items={left} />
          <List label="Filters" items={right} />
        </div>
      </div>
    </KeyboardProvider>
  );
}
